const body = $input.first().json.body;

// Validate required fields
if (!body.business_name || !body.email || !body.primary_region) {
  return [{json: {error: 'Missing required fields', status: 400}}];
}

// Generate client_id from business name
const clientId = body.business_name
  .replace(/[^a-zA-Z0-9]/g, '-')
  .replace(/-+/g, '-')
  .replace(/^-|-$/g, '')
  .toUpperCase();

// Build locations array (primary + additional)
const locations = [body.primary_region];
if (body.locations) {
  const additional = Array.isArray(body.locations) ? body.locations : [body.locations];
  for (const loc of additional) {
    if (!locations.includes(loc)) locations.push(loc);
  }
}

// Build compliance array
const compliance = body.compliance || ['SOC2'];
const complianceList = Array.isArray(compliance) ? compliance : [compliance];

return [{
  json: {
    client_id: clientId,
    business_name: body.business_name,
    customer_email: body.email,
    customer_name: body.business_name,
    stripe_session_id: body.stripe_session_id || '',
    stripe_customer_id: body.stripe_customer_id || '',
    stripe_subscription_id: body.stripe_subscription_id || '',
    billing_period: body.billing_period || 'monthly',
    tier: 'enterprise',
    compliance: complianceList.join(','),
    locations: locations.join(','),
    primary_region: body.primary_region,
    industry: body.industry || 'general',
    brand_color: body.brand_color || '#001a2d',
    status: 'configuration_complete'
  }
}];
